//------------------------------------------------------------------------------
//Callback Name: update_cb
//------------------------------------------------------------------------------
int MaxDim::update_cb(NXOpen::BlockStyler::UIBlock* block)
{
	try
	{
		if (block == selection0)
		{
			UF_initialize();
			NXOpen::Session* theSession = NXOpen::Session::GetSession();
			NXOpen::Part* workPart(theSession->Parts()->Work());
			NXOpen::Part* displayPart(theSession->Parts()->Display());

			//获取UI界面的值,视图NXtag
			PropertyList* selection0Props = selection0->GetProperties();
			std::vector<NXOpen::TaggedObject*> View1Tag = selection0Props->GetTaggedObjectVector("SelectedObjects");
			delete selection0Props;
			selection0Props = NULL;
			if (View1Tag.empty() || View1Tag[0] == NULL)
			{
				UF_terminate();
				return 0;
			}

			//获取视图
			NXOpen::Drawings::DraftingView* draftingView1(dynamic_cast<NXOpen::Drawings::DraftingView*>(NXOpen::NXObjectManager::Get(View1Tag[0]->Tag())));
			if (draftingView1 == NULL)
			{
				UF_terminate();
				return 0;
			}

			std::vector<Drawings::DraftingBody*>DraftingBodyVector;
			//获取视图body
			Drawings::DraftingBodyCollection* DraftingBodyCollection1 = draftingView1->DraftingBodies();
			Drawings::DraftingBodyCollection::iterator Ite1 = DraftingBodyCollection1->begin();
			Drawings::DraftingBody* DraftingBody;
			for (; Ite1 != DraftingBodyCollection1->end(); ++Ite1)
			{
				DraftingBody = (*Ite1);
				DraftingBodyVector.push_back(DraftingBody);
			}

			std::vector<Drawings::DraftingCurve*>DraftingCurvevector;
			for (size_t i = 0; i < DraftingBodyVector.size(); i++)
			{
				// 获取视图Curve

				Drawings::DraftingCurve* DraftingCurve;
				Drawings::DraftingCurveCollection* DraftingCurveCollection1 = DraftingBodyVector[i]->DraftingCurves();
				Drawings::DraftingCurveCollection::iterator Ite2 = DraftingCurveCollection1->begin();
				for (; Ite2 != DraftingCurveCollection1->end(); ++Ite2)
				{
					DraftingCurve = (*Ite2);
					DraftingCurvevector.push_back(DraftingCurve);
				}
			}
			LayoutRect viewRect = { 0.0, 0.0, 0.0, 0.0 };
			if (AskLineCurveRect(draftingView1, DraftingCurvevector, viewRect))
			{
				CreateOverallDimensionForView(workPart, draftingView1, DraftingCurvevector, viewRect, true);
				CreateOverallDimensionForView(workPart, draftingView1, DraftingCurvevector, viewRect, false);
			}
			UF_terminate();

		}
	}
	catch (exception& ex)
		{
			//---- Enter your exception handling code here -----
			MaxDim::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
		}
		return 0;
	}

	//------------------------------------------------------------------------------
	//Callback Name: ok_cb
	//------------------------------------------------------------------------------
	int MaxDim::ok_cb()
	{
		int errorCode = 0;
		try
		{
			errorCode = apply_cb();
		}
		catch (exception& ex)
		{
        //---- Enter your exception handling code here -----
        errorCode = 1;
        MaxDim::theUI->NXMessageBox()->Show("Block Styler", NXOpen::NXMessageBox::DialogTypeError, ex.what());
    }
    return errorCode;
}

